import { Injectable, NotFoundException, ForbiddenException } from '@nestjs/common';
import { InjectQueue } from '@nestjs/bullmq';
import { Queue } from 'bullmq';
import { PrismaService } from '../database/prisma.service';
import { ScanStatus } from '@prisma/client';

@Injectable()
export class ScanService {
  constructor(
    private readonly prisma: PrismaService,
    @InjectQueue('scanner-queue') private readonly scannerQueue: Queue,
  ) {}

  async triggerScan(targetId: string, userId?: string) {
    const target = await this.prisma.target.findUnique({ 
      where: { id: targetId },
      include: { team: { include: { members: true } } }
    });

    if (!target) {
      throw new NotFoundException('Asset target mapping details not found');
    }

    // Authorization check: Verify user has access to this target
    if (userId && target.teamId) {
      const hasAccess = target.team.members.some(member => member.userId === userId);
      if (!hasAccess) {
        throw new ForbiddenException('You do not have permission to scan this target');
      }
    }

    const scan = await this.prisma.scan.create({
      data: {
        targetId,
        status: ScanStatus.PENDING,
      },
    });

    // Add job to BullMQ processing queue
    await this.scannerQueue.add('execute-scan', {
      scanId: scan.id,
      targetId: target.id,
      scope: target.scope,
      type: target.type,
    });

    return scan;
  }

