import { ScanService } from './scan.service';
import { CreateScanDto } from './dto/scan.dto';
import { AuthGuard } from '../auth/guards/auth.guard';

@UseGuards(AuthGuard)
@Controller('scans')
export class ScanController {
  constructor(private readonly scanService: ScanService) {}

  @Post()
  async triggerScan(@Body() dto: CreateScanDto, @Request() req: any) {
    const userId = req.user?.sub; // Extract userId from JWT payload
    return this.scanService.triggerScan(dto.targetId, userId);
  }

