import { Module } from '@nestjs/common';
import { AuthModule } from './auth/auth.module';
import { TargetModule } from './targets/target.module';
import { ScanModule } from './scans/scan.module';
import { AIModule } from './ai/ai.module';
import { VulnerabilityModule } from './vulnerabilities/vulnerability.module';
import { ListenerModule } from './listeners/listener.module';
import { DatabaseModule } from './database/database.module';
import { BullModule } from '@nestjs/bullmq';
import { ThrottlerModule, ThrottlerGuard } from '@nestjs/throttler';
import { APP_GUARD } from '@nestjs/core';

@Module({
  imports: [
    DatabaseModule,
    AuthModule,
    TargetModule,
    ScanModule,
    AIModule,
    VulnerabilityModule,
    ListenerModule,
    BullModule.forRoot({
      connection: {
        host: process.env.REDIS_HOST || 'localhost',
        port: parseInt(process.env.REDIS_PORT || '6379', 10),
      },
    }),
    // Rate limiting: 100 requests per 60 seconds per IP
    ThrottlerModule.forRoot([{
      ttl: 60000, // 60 seconds
      limit: 100, // 100 requests
    }]),
  ],
  providers: [
    // Apply rate limiting globally to all routes
    {
      provide: APP_GUARD,
      useClass: ThrottlerGuard,
    },
  ],
})
export class AppModule {}

