import { IsString, IsEnum } from 'class-validator';

export enum ReportFormat {
  PDF = 'PDF',
  MARKDOWN = 'MARKDOWN',
  JSON = 'JSON',
}

export class CreateReportDto {
  @IsString()
  title: string;

  @IsEnum(ReportFormat)
  format: ReportFormat;

  @IsString()
  targetId?: string;

  @IsString()
  scanId?: string;
}

import { Injectable, NotFoundException } from '@nestjs/common';
import { PrismaService } from '../database/prisma.service';
import { CreateReportDto, ReportFormat } from './dto/report.dto';
import * as fs from 'fs/promises';
import * as path from 'path';

@Injectable()
export class ReportService {
  private readonly reportsDir: string;

  constructor(private readonly prisma: PrismaService) {
    this.reportsDir = path.join(process.cwd(), 'reports');
    this.ensureReportsDirectory();
  }

  private async ensureReportsDirectory() {
    try {
      await fs.mkdir(this.reportsDir, { recursive: true });
    } catch (error) {
      console.error('Failed to create reports directory:', error);
    }
  }

  async create(userId: string, dto: CreateReportDto) {
    // Fetch data based on targetId or scanId
    let reportData: any = {};

    if (dto.targetId) {
      reportData = await this.getTargetReport(dto.targetId);
    } else if (dto.scanId) {
      reportData = await this.getScanReport(dto.scanId);
    } else {
      reportData = await this.getFullReport(userId);
    }

    // Generate report file
    const filename = await this.generateReport(dto.title, dto.format, reportData);
    const downloadUrl = `/reports/${filename}`;

    // Save to database
    const report = await this.prisma.report.create({
      data: {
        userId,
        title: dto.title,
        format: dto.format,
        downloadUrl,
      },
    });

    return report;
  }

  async findAll(userId: string) {
    return this.prisma.report.findMany({
      where: { userId },
      orderBy: { createdAt: 'desc' },
    });
  }

  async findOne(id: string, userId: string) {
    const report = await this.prisma.report.findFirst({
      where: { id, userId },
    });

    if (!report) {
      throw new NotFoundException('Report not found');
    }

    return report;
  }

  async delete(id: string, userId: string) {
    const report = await this.findOne(id, userId);

    // Delete file
    const filepath = path.join(this.reportsDir, path.basename(report.downloadUrl));
    try {
      await fs.unlink(filepath);
    } catch (error) {
      console.error('Failed to delete report file:', error);
    }

    // Delete from database
    return this.prisma.report.delete({ where: { id } });
  }

  private async getTargetReport(targetId: string) {
    const target = await this.prisma.target.findUnique({
      where: { id: targetId },
      include: {
        vulnerabilities: true,
        scans: {
          include: { logs: true },
          orderBy: { createdAt: 'desc' },
          take: 10,
        },
      },
    });

    if (!target) {
      throw new NotFoundException('Target not found');
    }

    return {
      type: 'target',
      target,
      vulnerabilities: target.vulnerabilities,
      scans: target.scans,
    };
  }

  private async getScanReport(scanId: string) {
    const scan = await this.prisma.scan.findUnique({
      where: { id: scanId },
      include: {
        target: {
          include: { vulnerabilities: true },
        },
        logs: true,
      },
    });

    if (!scan) {
      throw new NotFoundException('Scan not found');
    }

    return {
      type: 'scan',
      scan,
      target: scan.target,
      vulnerabilities: scan.target.vulnerabilities,
      logs: scan.logs,
    };
  }

  private async getFullReport(userId: string) {
    const user = await this.prisma.user.findUnique({
      where: { id: userId },
      select: { id: true, name: true, email: true },
    });

    const targets = await this.prisma.target.findMany({
      include: {
        vulnerabilities: true,
        scans: true,
      },
    });

    const vulnerabilities = await this.prisma.vulnerability.findMany({
      include: { target: true },
    });

    return {
      type: 'full',
      user,
      targets,
      vulnerabilities,
      summary: {
        totalTargets: targets.length,
        totalVulnerabilities: vulnerabilities.length,
        criticalCount: vulnerabilities.filter((v) => v.severity === 'CRITICAL').length,
        highCount: vulnerabilities.filter((v) => v.severity === 'HIGH').length,
        mediumCount: vulnerabilities.filter((v) => v.severity === 'MEDIUM').length,
        lowCount: vulnerabilities.filter((v) => v.severity === 'LOW').length,
      },
    };
  }

  private async generateReport(
    title: string,
    format: ReportFormat,
    data: any,
  ): Promise<string> {
    const timestamp = Date.now();
    const sanitizedTitle = title.replace(/[^a-z0-9]/gi, '_').toLowerCase();
    const filename = `${sanitizedTitle}_${timestamp}.${format.toLowerCase()}`;
    const filepath = path.join(this.reportsDir, filename);

    let content: string;

    switch (format) {
      case ReportFormat.MARKDOWN:
        content = this.generateMarkdown(title, data);
        break;
      case ReportFormat.JSON:
        content = JSON.stringify(data, null, 2);
        break;
      case ReportFormat.PDF:
        // TODO: Implement PDF generation (requires additional library)
        content = this.generateMarkdown(title, data);
        console.warn('PDF generation not yet implemented, falling back to Markdown');
        break;
      default:
        content = JSON.stringify(data, null, 2);
    }

    await fs.writeFile(filepath, content, 'utf-8');
    return filename;
  }

  private generateMarkdown(title: string, data: any): string {
    const lines: string[] = [];

    lines.push(`# ${title}`);
    lines.push('');
    lines.push(`**Generated:** ${new Date().toISOString()}`);
    lines.push('');
    lines.push('---');
    lines.push('');

    if (data.type === 'target') {
      lines.push(`## Target: ${data.target.name}`);
      lines.push('');
      lines.push(`- **Scope:** ${data.target.scope}`);
      lines.push(`- **Type:** ${data.target.type}`);
      lines.push(`- **Priority:** ${data.target.priority}`);
      lines.push('');
      lines.push(`### Vulnerabilities (${data.vulnerabilities.length})`);
      lines.push('');

      for (const vuln of data.vulnerabilities) {
        lines.push(`#### ${vuln.title}`);
        lines.push('');
        lines.push(`- **Severity:** ${vuln.severity}`);
        lines.push(`- **CVSS Score:** ${vuln.cvssScore}`);
        lines.push(`- **Type:** ${vuln.type}`);
        lines.push('');
        lines.push(`**Description:**`);
        lines.push(vuln.description);
        lines.push('');
        lines.push(`**Remediation:**`);
        lines.push(vuln.remediation);
        lines.push('');
      }
    } else if (data.type === 'scan') {
      lines.push(`## Scan Report`);
      lines.push('');
      lines.push(`- **Target:** ${data.target.name} (${data.target.scope})`);
      lines.push(`- **Status:** ${data.scan.status}`);
      lines.push(`- **Started:** ${data.scan.startedAt}`);
      lines.push(`- **Finished:** ${data.scan.finishedAt || 'N/A'}`);
      lines.push('');
      lines.push(`### Scan Logs`);
      lines.push('');
      lines.push('```');
      for (const log of data.logs) {
        lines.push(`[${log.timestamp}] ${log.message}`);
      }
      lines.push('```');
      lines.push('');
    } else if (data.type === 'full') {
      lines.push(`## Full Security Report`);
      lines.push('');
      lines.push(`**User:** ${data.user.name} (${data.user.email})`);
      lines.push('');
      lines.push(`### Summary`);
      lines.push('');
      lines.push(`- **Total Targets:** ${data.summary.totalTargets}`);
      lines.push(`- **Total Vulnerabilities:** ${data.summary.totalVulnerabilities}`);
      lines.push(`  - Critical: ${data.summary.criticalCount}`);
      lines.push(`  - High: ${data.summary.highCount}`);
      lines.push(`  - Medium: ${data.summary.mediumCount}`);
      lines.push(`  - Low: ${data.summary.lowCount}`);
      lines.push('');
      lines.push(`### Vulnerabilities by Target`);
      lines.push('');

      for (const target of data.targets) {
        if (target.vulnerabilities.length > 0) {
          lines.push(`#### ${target.name}`);
          lines.push('');
          for (const vuln of target.vulnerabilities) {
            lines.push(`- **[${vuln.severity}]** ${vuln.title} (CVSS: ${vuln.cvssScore})`);
          }
          lines.push('');
        }
      }
    }

    lines.push('---');
    lines.push('');
    lines.push('*Generated by VulnX Hunter*');

    return lines.join('\n');
  }
}

import {
  Controller,
  Post,
  Get,
  Delete,
  Body,
  Param,
  UseGuards,
  Request,
  Res,
} from '@nestjs/common';
import { Response } from 'express';
import { ReportService } from './report.service';
import { CreateReportDto } from './dto/report.dto';
import { AuthGuard } from '../auth/guards/auth.guard';
import * as path from 'path';

@UseGuards(AuthGuard)
@Controller('reports')
export class ReportController {
  constructor(private readonly reportService: ReportService) {}

  @Post()
  async create(@Body() dto: CreateReportDto, @Request() req: any) {
    const userId = req.user.sub;
    return this.reportService.create(userId, dto);
  }

  @Get()
  async findAll(@Request() req: any) {
    const userId = req.user.sub;
    return this.reportService.findAll(userId);
  }

  @Get(':id')
  async findOne(@Param('id') id: string, @Request() req: any) {
    const userId = req.user.sub;
    return this.reportService.findOne(id, userId);
  }

  @Get(':id/download')
  async download(
    @Param('id') id: string,
    @Request() req: any,
    @Res() res: Response,
  ) {
    const userId = req.user.sub;
    const report = await this.reportService.findOne(id, userId);

    const filepath = path.join(
      process.cwd(),
      'reports',
      path.basename(report.downloadUrl),
    );

    res.download(filepath, (err) => {
      if (err) {
        console.error('Download error:', err);
        res.status(404).send('Report file not found');
      }
    });
  }

  @Delete(':id')
  async delete(@Param('id') id: string, @Request() req: any) {
    const userId = req.user.sub;
    return this.reportService.delete(id, userId);
  }
}

import { Module } from '@nestjs/common';
import { ReportService } from './report.service';
import { ReportController } from './report.controller';

@Module({
  controllers: [ReportController],
  providers: [ReportService],
  exports: [ReportService],
})
export class ReportModule {}

