package main

import (
	"encoding/json"
	"fmt"
	"log"
	"math/rand"
	"net/http"
	"strings"
	"time"
)

// Request structures
type ScanRequest struct {
	TargetID string `json:"targetId"`
	Scope    string `json:"scope"`
	Type     string `json:"type"`
}

// Response structures
type Vulnerability struct {
	Title       string  `json:"title"`
	Type        string  `json:"type"`
	Severity    string  `json:"severity"`
	CVSSScore   float64 `json:"cvssScore"`
	Description string  `json:"description"`
	Remediation string  `json:"remediation"`
}

type ScanResponse struct {
	Vulnerabilities []Vulnerability `json:"vulnerabilities"`
	Logs            []string        `json:"logs"`
}

// CORS middleware
func enableCORS(w http.ResponseWriter) {
	w.Header().Set("Access-Control-Allow-Origin", "*")
	w.Header().Set("Access-Control-Allow-Methods", "POST, GET, OPTIONS")
	w.Header().Set("Access-Control-Allow-Headers", "Content-Type, Authorization")
}

// Main scan handler
func handleScan(w http.ResponseWriter, r *http.Request) {
	enableCORS(w)

	if r.Method == http.MethodOptions {
		w.WriteHeader(http.StatusOK)
		return
	}

	if r.Method != http.MethodPost {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	var req ScanRequest
	err := json.NewDecoder(r.Body).Decode(&req)
	if err != nil {
		http.Error(w, "Bad request payload", http.StatusBadRequest)
		return
	}

	log.Printf("[*] Scanner Agent executing scan on: %s (%s)", req.Scope, req.Type)

	// Execute scan
	response := executeScan(req)

	w.Header().Set("Content-Type", "application/json")
	w.WriteHeader(http.StatusOK)
	json.NewEncoder(w).Encode(response)
}

// Execute scan with realistic simulation
func executeScan(req ScanRequest) ScanResponse {
	logs := []string{}
	vulnerabilities := []Vulnerability{}

	// Phase 1: Reconnaissance
	logs = append(logs, fmt.Sprintf("[*] Starting reconnaissance on target: %s", req.Scope))
	time.Sleep(500 * time.Millisecond)

	// Phase 2: Subdomain enumeration (for domains)
	if req.Type == "DOMAIN" {
		logs = append(logs, "[*] Enumerating subdomains...")
		time.Sleep(300 * time.Millisecond)
		subdomains := []string{"www", "mail", "ftp", "admin", "api", "dev"}
		logs = append(logs, fmt.Sprintf("[+] Found %d subdomains: %s.%s, %s.%s, %s.%s",
			len(subdomains), subdomains[0], req.Scope, subdomains[1], req.Scope, subdomains[2], req.Scope))
	}

	// Phase 3: Port scanning
	logs = append(logs, "[*] Starting port scan...")
	time.Sleep(400 * time.Millisecond)
	openPorts := []string{"80/tcp", "443/tcp", "22/tcp", "3306/tcp", "8080/tcp"}
	logs = append(logs, fmt.Sprintf("[+] Found %d open ports: %s", len(openPorts), strings.Join(openPorts, ", ")))

	// Phase 4: Service detection
	logs = append(logs, "[*] Detecting services on open ports...")
	time.Sleep(300 * time.Millisecond)
	logs = append(logs, "[+] Services detected: HTTP, HTTPS, SSH, MySQL, HTTP-Proxy")

	// Phase 5: Vulnerability scanning
	logs = append(logs, "[*] Running vulnerability detection templates...")
	time.Sleep(500 * time.Millisecond)

	// Generate vulnerabilities based on target type
	vulnerabilities = generateVulnerabilities(req)

	for _, vuln := range vulnerabilities {
		logs = append(logs, fmt.Sprintf("[!] VULNERABILITY FOUND: %s [%s]", vuln.Title, vuln.Severity))
	}

	logs = append(logs, "[+] Scan completed successfully")

	return ScanResponse{
		Vulnerabilities: vulnerabilities,
		Logs:            logs,
	}
}

// Generate realistic vulnerabilities
func generateVulnerabilities(req ScanRequest) []Vulnerability {
	vulnerabilities := []Vulnerability{}
	rand.Seed(time.Now().UnixNano())

	// Common vulnerabilities for all types
	commonVulns := []Vulnerability{
		{
			Title:       "Open SSH Port Exposed to Internet",
			Type:        "Port Exposure",
			Severity:    "LOW",
			CVSSScore:   3.5,
			Description: fmt.Sprintf("Target %s has SSH port 22 open and accessible from the internet, potentially allowing brute-force attacks.", req.Scope),
			Remediation: "Restrict SSH access to specific IP addresses using firewall rules. Implement fail2ban or similar brute-force protection.",
		},
		{
			Title:       "Missing Security Headers",
			Type:        "Configuration",
			Severity:    "MEDIUM",
			CVSSScore:   5.3,
			Description: "Web server is missing critical security headers: X-Frame-Options, X-Content-Type-Options, Content-Security-Policy.",
			Remediation: "Configure web server to include security headers. Use helmet.js for Node.js applications or equivalent for other platforms.",
		},
	}

	// Domain-specific vulnerabilities
	if req.Type == "DOMAIN" {
		domainVulns := []Vulnerability{
			{
				Title:       "Outdated jQuery Library Detected",
				Type:        "Known Vulnerable Component",
				Severity:    "MEDIUM",
				CVSSScore:   5.6,
				Description: fmt.Sprintf("Website at %s uses jQuery v1.12.4 which contains known XSS vulnerabilities (CVE-2020-11022, CVE-2020-11023).", req.Scope),
				Remediation: "Upgrade jQuery to version 3.7.0 or later. Review and update all JavaScript dependencies.",
			},
			{
				Title:       "Subdomain Takeover Possible",
				Type:        "DNS Misconfiguration",
				Severity:    "HIGH",
				CVSSScore:   7.5,
				Description: fmt.Sprintf("Subdomain dev.%s points to unclaimed cloud resource, allowing potential subdomain takeover.", req.Scope),
				Remediation: "Remove DNS records for unused subdomains or claim the cloud resources they point to.",
			},
		}
		vulnerabilities = append(vulnerabilities, domainVulns...)
	}

	// IP-specific vulnerabilities
	if req.Type == "IP" {
		ipVulns := []Vulnerability{
			{
				Title:       "MySQL Server Exposed on Default Port",
				Type:        "Service Exposure",
				Severity:    "HIGH",
				CVSSScore:   7.3,
				Description: fmt.Sprintf("MySQL database server is accessible on %s:3306 from the internet without IP restrictions.", req.Scope),
				Remediation: "Configure MySQL to bind only to localhost or use firewall rules to restrict access to trusted IPs only.",
			},
		}
		vulnerabilities = append(vulnerabilities, ipVulns...)
	}

	// Add some common vulnerabilities
	vulnerabilities = append(vulnerabilities, commonVulns...)

	// Randomly add a critical vulnerability (30% chance)
	if rand.Float32() < 0.3 {
		criticalVuln := Vulnerability{
			Title:       "SQL Injection in Login Form",
			Type:        "Injection",
			Severity:    "CRITICAL",
			CVSSScore:   9.8,
			Description: fmt.Sprintf("SQL injection vulnerability detected in login endpoint at %s/login. Allows authentication bypass and database access.", req.Scope),
			Remediation: "Use parameterized queries or prepared statements. Implement input validation and sanitization. Use ORM frameworks that prevent SQL injection.",
		}
		vulnerabilities = append(vulnerabilities, criticalVuln)
	}

	return vulnerabilities
}

// Health check endpoint
func handleHealth(w http.ResponseWriter, r *http.Request) {
	enableCORS(w)
	w.Header().Set("Content-Type", "application/json")
	json.NewEncoder(w).Encode(map[string]string{
		"status":  "healthy",
		"service": "vulnx-scanner",
		"version": "1.0.0",
	})
}

func main() {
	http.HandleFunc("/scan", handleScan)
	http.HandleFunc("/health", handleHealth)

	port := "8080"
	log.Printf("🚀 VulnX Scanner Service started on port %s", port)
	log.Printf("📡 Endpoints:")
	log.Printf("   POST /scan   - Execute vulnerability scan")
	log.Printf("   GET  /health - Health check")

	if err := http.ListenAndServe(":"+port, nil); err != nil {
		log.Fatalf("❌ Scanner service failed to start: %v", err)
	}
}

